package Simple_Conditions;

public class Exe_1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		// Check Even or Odd 
		// Take an integer and check if it is even or odd.
		
		int num = 7;
		
		if (num % 2 == 0 ) {
			System.out.println("Even");
		}
		else {
			System.out.println("Odd");
		}
	}

}
